import { TypeNode } from "../../ir/ast.js";
import { swiftFunctionName, swiftModuleName, swiftPropertyName, swiftStringLiteral, swiftTypeName } from "./identifiers.js";

export function emitSwiftRuntime(moduleName: string): string {
  return [
    "// Code generated by Typra emitter; DO NOT EDIT.",
    "",
    "import Foundation",
    "import Yams",
    "",
    "public struct LoadContext {",
    "  public init() {}",
    "}",
    "",
    "public struct SaveContext {",
    "  public init() {}",
    "}",
    "",
    "public enum TypraRuntimeError: Error, CustomStringConvertible {",
    "  case invalidObject(type: String)",
    "  case invalidField(field: String, expected: String)",
    "  case invalidEnum(type: String, value: String)",
    "  case unknownDiscriminator(type: String, field: String, value: String)",
    "  case unsupported(String)",
    "",
    "  public var description: String {",
    "    switch self {",
    "    case .invalidObject(let type): return \"Expected object for \\(type).\"",
    "    case .invalidField(let field, let expected): return \"Expected \\(expected) for field \\(field).\"",
    "    case .invalidEnum(let type, let value): return \"Invalid \\(type) value: \\(value).\"",
    "    case .unknownDiscriminator(let type, let field, let value): return \"Unknown \\(type) discriminator \\(field)=\\(value).\"",
    "    case .unsupported(let message): return message",
    "    }",
    "  }",
    "}",
    "",
    "public protocol TypraModel {",
    "  static func load(_ data: Any, context: LoadContext) throws -> Self",
    "  func save(_ context: SaveContext) throws -> [String: Any]",
    "}",
    "",
    "public enum TypraRuntime {",
    "  public static func object(_ data: Any, typeName: String) throws -> [String: Any] {",
    "    guard let object = data as? [String: Any] else { throw TypraRuntimeError.invalidObject(type: typeName) }",
    "    return object",
    "  }",
    "",
    "  public static func dictionary(_ data: Any, field: String) throws -> [String: Any] {",
    "    guard let object = data as? [String: Any] else { throw TypraRuntimeError.invalidField(field: field, expected: \"dictionary\") }",
    "    return object",
    "  }",
    "",
    "  public static func array(_ data: Any, field: String) throws -> [Any] {",
    "    guard let array = data as? [Any] else { throw TypraRuntimeError.invalidField(field: field, expected: \"array\") }",
    "    return array",
    "  }",
    "",
    "  public static func string(_ data: Any, field: String) throws -> String {",
    "    guard let value = data as? String else { throw TypraRuntimeError.invalidField(field: field, expected: \"string\") }",
    "    return value",
    "  }",
    "",
    "  public static func bool(_ data: Any, field: String) throws -> Bool {",
    "    if let value = data as? Bool { return value }",
    "    if let number = data as? NSNumber, isBoolNumber(number) { return number.boolValue }",
    "    throw TypraRuntimeError.invalidField(field: field, expected: \"boolean\")",
    "  }",
    "",
    "  public static func double(_ data: Any, field: String) throws -> Double {",
    "    if let value = data as? Double { return value }",
    "    if let value = data as? Float { return Double(value) }",
    "    if let value = data as? Int { return Double(value) }",
    "    if let value = data as? Int64 { return Double(value) }",
    "    if let number = data as? NSNumber { return number.doubleValue }",
    "    throw TypraRuntimeError.invalidField(field: field, expected: \"number\")",
    "  }",
    "",
    "  public static func float(_ data: Any, field: String) throws -> Float {",
    "    return Float(try double(data, field: field))",
    "  }",
    "",
    "  public static func int(_ data: Any, field: String) throws -> Int {",
    "    let value = try int64(data, field: field)",
    "    guard value >= Int64(Int.min) && value <= Int64(Int.max) else { throw TypraRuntimeError.invalidField(field: field, expected: \"integer\") }",
    "    return Int(value)",
    "  }",
    "",
    "  public static func int32(_ data: Any, field: String) throws -> Int32 {",
    "    let value = try int64(data, field: field)",
    "    guard value >= Int64(Int32.min) && value <= Int64(Int32.max) else { throw TypraRuntimeError.invalidField(field: field, expected: \"int32\") }",
    "    return Int32(value)",
    "  }",
    "",
    "  public static func int64(_ data: Any, field: String) throws -> Int64 {",
    "    if let value = data as? NSNumber, !isBoolNumber(value) {",
    "      return try exactInt64(value, field: field)",
    "    }",
    "    if let value = data as? Int64 { return value }",
    "    if let value = data as? Int { return Int64(value) }",
    "    if let value = data as? Int32 { return Int64(value) }",
    "    throw TypraRuntimeError.invalidField(field: field, expected: \"integer\")",
    "  }",
    "",
    "  private static func exactInt64(_ number: NSNumber, field: String) throws -> Int64 {",
    "    switch String(cString: number.objCType) {",
    "    case \"s\", \"i\", \"l\", \"q\":",
    "      return number.int64Value",
    "    case \"C\", \"S\", \"I\", \"L\", \"Q\":",
    "      let value = number.uint64Value",
    "      guard value <= UInt64(Int64.max) else { throw TypraRuntimeError.invalidField(field: field, expected: \"int64\") }",
    "      return Int64(value)",
    "    default:",
    "      break",
    "    }",
    "    var decimal = number.decimalValue",
    "    var minimum = Decimal(string: \"-9223372036854775808\")!",
    "    var maximum = Decimal(string: \"9223372036854775807\")!",
    "    guard NSDecimalCompare(&decimal, &minimum) != .orderedAscending && NSDecimalCompare(&decimal, &maximum) != .orderedDescending else { throw TypraRuntimeError.invalidField(field: field, expected: \"int64\") }",
    "    var rounded = Decimal()",
    "    NSDecimalRound(&rounded, &decimal, 0, .plain)",
    "    guard NSDecimalCompare(&rounded, &decimal) == .orderedSame else { throw TypraRuntimeError.invalidField(field: field, expected: \"integer\") }",
    "    guard let parsed = Int64(NSDecimalNumber(decimal: rounded).stringValue) else { throw TypraRuntimeError.invalidField(field: field, expected: \"int64\") }",
    "    return parsed",
    "  }",
    "",
    "  private static func isBoolNumber(_ number: NSNumber) -> Bool {",
    "    let type = String(cString: number.objCType)",
    "    return type == \"c\" || type == \"B\"",
    "  }",
    "",
    "  public static func jsonObject(from json: String, typeName: String) throws -> Any {",
    "    guard let data = json.data(using: .utf8) else { throw TypraRuntimeError.invalidObject(type: typeName) }",
    "    return try JSONSerialization.jsonObject(with: data, options: [])",
    "  }",
    "",
    "  public static func jsonString(from value: Any) throws -> String {",
    "    let data = try JSONSerialization.data(withJSONObject: value, options: [.sortedKeys])",
    "    return String(data: data, encoding: .utf8) ?? \"{}\"",
    "  }",
    "",
    "  public static func yamlObject(from yaml: String, typeName: String) throws -> Any {",
    "    guard let value = try Yams.load(yaml: yaml) else { throw TypraRuntimeError.invalidObject(type: typeName) }",
    "    return value",
    "  }",
    "",
    "  public static func yamlString(from value: Any) throws -> String {",
    "    return try Yams.dump(object: value)",
    "  }",
    "}",
    "",
  ].join("\n");
}

export function emitSwiftPackage(moduleName: string, testPath?: string): string {
  const targets = [
    `    .target(name: ${swiftStringLiteral(moduleName)}, dependencies: [.product(name: "Yams", package: "Yams")], path: "Sources/${moduleName}")`,
    ...(testPath ? [`    .testTarget(name: ${swiftStringLiteral(`${moduleName}Tests`)}, dependencies: [${swiftStringLiteral(moduleName)}], path: ${swiftStringLiteral(testPath)})`] : []),
  ];
  return [
    "// swift-tools-version: 5.9",
    "import PackageDescription",
    "",
    `let package = Package(`,
    `  name: ${swiftStringLiteral(moduleName)},`,
    "  platforms: [.macOS(.v12), .iOS(.v15)],",
    `  products: [.library(name: ${swiftStringLiteral(moduleName)}, targets: [${swiftStringLiteral(moduleName)}])],`,
    "  dependencies: [",
    "    .package(url: \"https://github.com/jpsim/Yams.git\", from: \"5.1.3\")",
    "  ],",
    "  targets: [",
    targets.join(",\n"),
    "  ]",
    ")",
    "",
  ].join("\n");
}

export function emitSwiftProtocolScaffolds(protocols: TypeNode[], moduleName: string): string {
  if (protocols.length === 0) return "";
  const lines = [
    "// Code generated by Typra emitter; DO NOT EDIT.",
    "",
    "import XCTest",
    `@testable import ${moduleName}`,
    "",
    "final class ProtocolScaffoldsTests: XCTestCase {",
    "  func testCompileOnlyProtocolScaffolds() {",
  ];
  for (const protocol of protocols) {
    const protocolName = swiftTypeName(protocol.typeName.name);
    const className = `CompileOnly${protocolName}`;
    lines.push(`    final class ${className}: ${protocolName} {`);
    for (const method of protocol.methods) {
      const params = Object.entries(method.params)
        .map(([name, typeName]) => `${swiftPropertyName(name)}: ${swiftProtocolType(typeName)}`)
        .join(", ");
      const asyncToken = method.sync ? "" : " async";
      const returnType = swiftProtocolType(method.returns);
      lines.push(`      func ${swiftFunctionName(method.name)}(${params})${asyncToken} throws${returnType === "Void" ? "" : ` -> ${returnType}`} {`);
      if (returnType !== "Void") {
        lines.push(`        throw TypraRuntimeError.unsupported(${swiftStringLiteral(`${protocolName}.${method.name} is a compile-only protocol scaffold.`)})`);
      } else {
        lines.push(`        throw TypraRuntimeError.unsupported(${swiftStringLiteral(`${protocolName}.${method.name} is a compile-only protocol scaffold.`)})`);
      }
      lines.push("      }");
    }
    lines.push("    }");
    lines.push(`    let ${swiftPropertyName(protocolName)}: ${protocolName} = ${className}()`);
    lines.push(`    _ = ${swiftPropertyName(protocolName)}`);
  }
  lines.push("  }");
  lines.push("}");
  lines.push("");
  return lines.join("\n");
}

function swiftProtocolType(typeName: string): string {
  const lower = typeName.toLowerCase();
  switch (lower) {
    case "void": return "Void";
    case "unknown":
    case "any": return "Any";
    case "string": return "String";
    case "boolean": return "Bool";
    case "int32": return "Int32";
    case "int64": return "Int64";
    case "integer": return "Int";
    case "float32": return "Float";
    case "float64":
    case "float":
    case "number":
    case "numeric": return "Double";
    default: return swiftTypeName(typeName);
  }
}

export { swiftModuleName };
